mapper.select:
SELECT
    bm.ID, bm.CONTENT, bm.NICKNAME, bm.AVATAR, bm.IP, bm.IP_REGION,
    bm.AUDIT_STATUS, bm.AUDIT_REASON, bm.AUDIT_TIME, bm.COLOR, bm.CREATE_TIME,
    (SELECT USERNAME FROM user u WHERE u.ID = bm.AUDIT_USER_ID) AS AUDIT_USERNAME
FROM barrage_message bm



        AND bm.CONTENT LIKE #{contentBind}



        AND bm.NICKNAME LIKE #{nicknameBind}


        AND bm.THEME_TYPE = #{query.ip}


        AND bm.AUDIT_STATUS = #{query.auditStatus}


ORDER BY bm.CREATE_TIME DESC
